import requests

response = requests.post(
    'https://api.pinelabs.com/v1/orders',
    headers={
        'Content-Type': 'application/json',
        'Authorization': 'Bearer YOUR_API_KEY'
    },
    json={
        'order_amount': 10000,
        'order_currency': 'INR',
        'customer_id': 'cust_12345',
        'order_note': 'Test order'
    }
)
print(response.json())
